SELECT 
FROM   USER_TRUSTED_DEVICES
WHERE  user_id        = #{userId}
  AND  device_id_hash = #{deviceIdHash}
  AND  status_code    = 'ACTIVE'
  AND  deleted_yn     = 'N'

SELECT 
FROM   USER_TRUSTED_DEVICES
WHERE  device_trust_id = #{deviceTrustId}
  AND  user_id         = #{userId}
  AND  deleted_yn      = 'N'

SELECT CASE WHEN COUNT(1) > 0 THEN 1 ELSE 0 END
FROM   USER_TRUSTED_DEVICES
WHERE  user_id        = #{userId}
  AND  device_id_hash = #{deviceIdHash}
  AND  deleted_yn     = 'N'

