UPDATE USER_TRUSTED_DEVICES
SET    last_used_at = SYSTIMESTAMP AT TIME ZONE 'Asia/Seoul'
WHERE  device_trust_id = #{deviceTrustId}

UPDATE USER_TRUSTED_DEVICES
SET    device_name = #{deviceName}
WHERE  device_trust_id = #{deviceTrustId}
  AND  user_id         = #{userId}
  AND  deleted_yn      = 'N'
